import sqlite3

try:
    conn = sqlite3.connect('users.db')
    cursor = conn.cursor()
    cursor.execute("SELECT email FROM users WHERE is_active = 1")
    rows = cursor.fetchall()
    for row in rows:
        print(row[0])
except sqlite3.Error as e:
    print(f"Database error: {e}")
finally:
    if conn:
        conn.close()
